def _e(title, diff, tags, desc, criteria, task_type=""):
    """Compact exercise dict constructor."""
    return {
        "title": title,
        "difficulty": diff,
        "tags": tags,
        "description": desc,
        "acceptance_criteria": criteria,
        "task_type": task_type,
    }


